const raw = $input.first().json;
const payload = raw.body || raw;
const headers = raw.headers || {};
const authHeader = headers.authorization || headers.Authorization || '';
if (authHeader !== 'Bearer ' + $env.DASHBOARD_API_TOKEN) {
  throw new Error('Unauthorized');
}
const topic_id = payload.topic_id;
if (!topic_id) throw new Error('topic_id is required');
const input_mode = (payload.input_mode === 'topic') ? 'topic' : 'script';
return [{ json: {
  topic_id,
  input_mode,
  topic_research_brief: payload.topic_research_brief || '',
  topic_angle: payload.topic_angle || '',
  seo_title_override: payload.seo_title || ''
} }];

const { topic_id, input_mode, topic_research_brief, topic_angle, seo_title_override } = $input.first().json;
const inputMode = input_mode || 'script';
const SB = $env.SUPABASE_URL;
const SRK = $env.SUPABASE_SERVICE_ROLE_KEY;
const AK = $env.ANTHROPIC_API_KEY;
const sbHeaders = { 'apikey': SRK, 'Authorization': `Bearer ${SRK}`, 'Content-Type': 'application/json' };

// 1. Read topic
const topicRes = await fetch(`${SB}/rest/v1/topics?id=eq.${topic_id}&select=id,project_id,seo_title,original_title,narrative_hook,script_json,scene_count,country_target`, { headers: sbHeaders });
const topicArr = await topicRes.json();
const topic = topicArr[0];
if (!topic) throw new Error('Topic not found: ' + topic_id);

// 2. Resolve combined_text
//    input_mode='topic': use topic_research_brief + topic_angle + seo_title (pre-script classification)
//    input_mode='script' (default): use script_json or scenes narration
let combined = null;
if (inputMode === 'topic') {
  combined = [
    topic_research_brief || '',
    topic_angle || '',
    seo_title_override || topic.seo_title || topic.original_title || '',
    topic.narrative_hook || ''
  ].filter(Boolean).join('\n\n');
}
const sj = topic.script_json;
if (!combined && sj && typeof sj === 'object' && !Array.isArray(sj)) {
  // Object form: {combined_text, pass_1, pass_2, pass_3}
  combined = sj.combined_text;
  if (!combined && sj.pass_1 && sj.pass_2 && sj.pass_3) {
    combined = sj.pass_1 + '\n\n' + sj.pass_2 + '\n\n' + sj.pass_3;
  }
}
if (!combined && Array.isArray(sj)) {
  // Array form: scenes_array inlined into script_json
  combined = sj.map(s => s.narration_text || '').filter(Boolean).join(' ');
}
if (!combined && typeof sj === 'string') {
  // Stringified array form (our current stuck topic is this)
  try {
    const parsed = JSON.parse(sj);
    if (Array.isArray(parsed)) {
      combined = parsed.map(s => s.narration_text || '').filter(Boolean).join(' ');
    }
  } catch (e) { /* fall through */ }
}
if (!combined) {
  // Final fallback: aggregate narration from scenes table
  const scRes = await fetch(`${SB}/rest/v1/scenes?topic_id=eq.${topic_id}&select=scene_number,narration_text&order=scene_number.asc`, { headers: sbHeaders });
  const scenes = await scRes.json();
  if (Array.isArray(scenes) && scenes.length > 0) {
    combined = scenes.map(s => s.narration_text || '').filter(Boolean).join(' ');
  }
}
if (!combined) throw new Error('No text available for register analysis (input_mode=' + inputMode + ') for topic ' + topic_id);

// 3. Trim to ~4k words (first 3k + last 1k)
const words = combined.split(/\s+/);
const sample = words.length <= 4000
  ? combined
  : words.slice(0, 3000).join(' ') + '\n\n[... middle truncated ...]\n\n' + words.slice(-1000).join(' ');

// 4. Build classifier prompt
const system = 'You are a cinematic production-register classifier for a YouTube documentary platform. Return ONLY valid JSON, no markdown, no commentary.';

const user = `Classify the script excerpt below into the top 2 best-fit Production Registers from these 5:\n\nREGISTER_01_ECONOMIST — documentary explainer. Analytical language, data citations, numeric density, comparison words ("versus," "compared to"), definition language. Default for unclassified explainer content across finance, legal, tax, B2B, real estate.\n\nREGISTER_02_PREMIUM — luxury editorial. Luxury product names (Platinum, Reserve, Centurion, Sotheby's, Private Client), lifestyle descriptors (marble, leather, first class, mahogany), dollar figures >$10K, wealth/legacy language, luxury real-estate content, HNW personal finance.\n\nREGISTER_03_NOIR — true-crime investigation. Investigation language ("scheme," "fraud," "predatory," "exposed," "hidden"), past-tense narrative about wrongdoing, legal/regulatory content, whistleblower or victim testimony, crime content, revenge stories in present-tense investigative framing.\n\nREGISTER_04_SIGNAL — tech/fintech precision. Technical terminology (algorithm, blockchain, tokenization, API, neural network), future-framing, fintech/AI/cyber content, B2B SaaS reviews and tutorials, product-technology mechanics.\n\nREGISTER_05_ARCHIVE — historical/biographical/intimate. Past-tense with year references, biographical language (birth, upbringing, meeting), historical-era markers, founder/origin stories, family drama with retrospective framing, revenge stories framed as slow-burn biographical, real-estate mogul histories.\n\nAlso detect the dominant era if REGISTER_05_ARCHIVE is in the top 2. Era is one of: "1920s", "1960s", "1980s", "2000s", "modern". Null if not applicable.\n\nAlso classify the niche variant for the top-ranked register:\n- REGISTER_01_ECONOMIST: one of "primary", "real_estate", "legal_tax"\n- REGISTER_02_PREMIUM: one of "primary", "real_estate", "travel_lifestyle"\n- REGISTER_03_NOIR: one of "primary", "financial_fraud", "dark_family"\n- REGISTER_04_SIGNAL: one of "primary", "crypto_payment", "cybersecurity"\n- REGISTER_05_ARCHIVE: "primary" (era_detected already handles variation)\nDefault to "primary" when uncertain.\n\nReturn this exact JSON shape:\n{\n  "all_5_ranked": [ { "register_id": "REGISTER_XX", "confidence": 0.0-1.0, "reasoning": "one sentence" } , ...5 entries in descending confidence ],\n  "top_2": [ { "register_id": "REGISTER_XX", "confidence": 0.0-1.0, "reasoning": "2-3 sentence paragraph explaining why this register fits the script", "reference_channels": ["Channel Name 1", "Channel Name 2"] }, ... ],\n  "era_detected": "1960s" | null,\n  "niche_variant": "primary" | "real_estate" | "legal_tax" | "travel_lifestyle" | "financial_fraud" | "dark_family" | "crypto_payment" | "cybersecurity",\n  "notes": "one-sentence classifier observation"\n}\n\nVideo title: ${topic.seo_title || topic.original_title || ''}\nNarrative hook: ${topic.narrative_hook || ''}\n\nScript excerpt:\n---\n${sample}\n---`;

// === BEGIN AU OVERLAY (migration 034) — append AU sub-niche addendum if applicable
let userPrompt = user;
if ((topic.country_target || 'GENERAL') === 'AU') {
  try {
    const addRes = await fetch(`${SB}/rest/v1/system_prompts?prompt_type=eq.register_classify_au_addendum&is_active=eq.true&select=prompt_text`, { headers: sbHeaders });
    if (addRes.ok) {
      const addRows = await addRes.json();
      const addendum = (addRows && addRows[0] && addRows[0].prompt_text) || '';
      if (addendum) userPrompt = userPrompt + '\n\n=== AU NICHE-VARIANT ADDENDUM ===\n' + addendum;
    }
  } catch (_) { /* leave userPrompt unchanged on failure */ }
}
// === END AU OVERLAY ===

// 5. Call Claude Haiku
const claudeRes = await fetch('https://api.anthropic.com/v1/messages', {
  method: 'POST',
  headers: { 'x-api-key': AK, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
  body: JSON.stringify({ model: 'claude-haiku-4-5-20251001', max_tokens: 2000, system, messages: [{ role: 'user', content: userPrompt }] })
});
if (!claudeRes.ok) {
  const err = await claudeRes.text();
  throw new Error(`Claude ${claudeRes.status}: ${err.slice(0, 400)}`);
}
const claudeData = await claudeRes.json();
const responseText = (claudeData.content || []).filter(c => c.type === 'text').map(c => c.text).join('');

let analysis;
try {
  const cleaned = responseText.replace(/^```(?:json)?\s*/m, '').replace(/\s*```\s*$/m, '').trim();
  const s = cleaned.indexOf('{');
  const e = cleaned.lastIndexOf('}');
  if (s < 0 || e <= s) throw new Error('No JSON object found');
  analysis = JSON.parse(cleaned.substring(s, e + 1));
} catch (err) {
  throw new Error(`Parse failed: ${err.message} — raw: ${responseText.slice(0, 300)}`);
}

if (!analysis.top_2 || !Array.isArray(analysis.top_2) || analysis.top_2.length < 2) {
  throw new Error('Invalid analysis shape: top_2 missing or < 2 entries');
}

const recommendations = { analyzed_at: new Date().toISOString(), model: 'claude-haiku-4-5-20251001', ...analysis };

// Auto-suggest top pick as production_register — user confirms at Gate 1 (register_selected_at stays null)
const topPickRegisterId = (analysis.top_2 && analysis.top_2[0] && analysis.top_2[0].register_id) || null;
const patchBody = {
  register_recommendations: recommendations,
  register_analyzed_at: new Date().toISOString(),
  register_era_detected: analysis.era_detected || null,
  niche_variant: analysis.niche_variant || 'primary',
  production_register: topPickRegisterId,
  updated_at: new Date().toISOString()
};

const patchRes = await fetch(`${SB}/rest/v1/topics?id=eq.${topic_id}`, {
  method: 'PATCH',
  headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
  body: JSON.stringify(patchBody)
});
if (!patchRes.ok) {
  const err = await patchRes.text();
  throw new Error(`PATCH failed ${patchRes.status}: ${err.slice(0, 300)}`);
}

await fetch(`${SB}/rest/v1/production_logs`, {
  method: 'POST',
  headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
  body: JSON.stringify({ topic_id, stage: 'register_analyze', action: 'completed', status: 'success', metadata: { input_mode: inputMode, top_2: analysis.top_2.map(r => ({ register_id: r.register_id, confidence: r.confidence })), era_detected: analysis.era_detected, niche_variant: analysis.niche_variant || 'primary', model: 'claude-haiku-4-5-20251001' } })
}).catch(e => console.warn('Log failed (non-fatal): ' + e.message));

return [{ json: { success: true, topic_id, top_2: analysis.top_2, era_detected: analysis.era_detected, niche_variant: analysis.niche_variant || 'primary', input_mode: inputMode } }];
